const body=$input.first().json.body||$input.first().json;
if(body.event!=='messages.upsert')return[];
const data=body.data||{};
if(data.key?.fromMe===true)return[];
const msgType=data.messageType||'';
const ALLOWED=['conversation','extendedTextMessage','imageMessage','audioMessage','documentMessage','videoMessage','stickerMessage','documentWithCaptionMessage'];
if(!ALLOWED.includes(msgType))return[];
const remoteJid=data.key?.remoteJid||'';
let phone=remoteJid.replace(/@.+/,'');
if(remoteJid.includes('@lid')){const jidAlt=(body.key&&body.key.remoteJidAlt)||'';if(jidAlt&&jidAlt.includes('@s.whatsapp.net')){phone=jidAlt.replace(/@.+/,'');}else{const sender=body.sender||'';phone=sender?sender.replace(/@.+/,''):remoteJid.split('@')[0];}}
const isAudio=msgType==='audioMessage';
const isImage=msgType==='imageMessage';
const isDocument=msgType==='documentMessage'||msgType==='documentWithCaptionMessage';
const isVideo=msgType==='videoMessage';
const isSticker=msgType==='stickerMessage';
const isAttachment=isAudio||isImage||isDocument||isVideo||isSticker;
const msg=data.message||{};
const docNode=msg.documentMessage||msg.documentWithCaptionMessage?.message?.documentMessage||{};
const imgNode=msg.imageMessage||{};
const vidNode=msg.videoMessage||{};
const audNode=msg.audioMessage||{};
const stkNode=msg.stickerMessage||{};
const content=isAudio?'':(msg.conversation||msg.extendedTextMessage?.text||imgNode.caption||docNode.caption||vidNode.caption||'');
if(!phone||(!content.trim()&&!isAttachment))return[];
const audioBase64=isAudio?(audNode.base64||data.base64||msg.base64||data.mediaData?.base64||''):'';
const audioMime=isAudio?(audNode.mimetype||data.mimetype||'audio/ogg'):'';
const imageBase64=isImage?(imgNode.base64||data.base64||msg.base64||data.mediaData?.base64||''):'';
const imageMime=isImage?(imgNode.mimetype||'image/jpeg'):'';
const imageCaption=isImage?(imgNode.caption||''):'';
let attNode=null,attKind='';
if(isImage){attNode=imgNode;attKind='image';}
else if(isAudio){attNode=audNode;attKind='audio';}
else if(isDocument){attNode=docNode;attKind='document';}
else if(isVideo){attNode=vidNode;attKind='video';}
else if(isSticker){attNode=stkNode;attKind='sticker';}
const attachmentBase64=attNode?(attNode.base64||data.base64||msg.base64||data.mediaData?.base64||''):'';
const attachmentMime=attNode?(attNode.mimetype||''):'';
let attachmentFilename='';
if(isDocument){attachmentFilename=docNode.fileName||docNode.title||`documento.${(attachmentMime||'application/pdf').split('/')[1]||'bin'}`;}
else if(isImage){const ext=(imageMime||'image/jpeg').split('/')[1]||'jpg';attachmentFilename=`imagem_${Date.now()}.${ext}`;}
else if(isVideo){const ext=(attachmentMime||'video/mp4').split('/')[1]||'mp4';attachmentFilename=`video_${Date.now()}.${ext}`;}
else if(isAudio){const ext=(audioMime||'audio/ogg').split('/')[1]||'ogg';attachmentFilename=`audio_${Date.now()}.${ext.replace(';','')}`;}
else if(isSticker){attachmentFilename=`sticker_${Date.now()}.webp`;}
const attachmentCaption=attNode?(attNode.caption||''):'';
const rawData=isAttachment?data:null;
return[{json:{instance:body.instance,phone,remoteJid,pushName:data.pushName||phone,content:content.trim(),isAudio,audioBase64,audioMime,isImage,imageBase64,imageMime,imageCaption,isDocument,isVideo,isSticker,isAttachment,attachmentBase64,attachmentMime,attachmentFilename,attachmentCaption,attachmentKind:attKind,rawData,crm_retorno:body._crm_retorno===true,crm_contato_id:body._crm_contato_id||null,receivedAt:Date.now()}}];

const resp=$input.first().json;
const rows=resp.body||[];
if(!Array.isArray(rows)||!rows.length||!rows[0].id)return[];
const cliente=rows[0];
const msg=$('Consolida').first().json;

const ignorados = cliente.numeros_ignorados || [];
if (ignorados.includes(msg.phone)) return [];

const keywords=cliente.handoff_keywords||['atendente','humano','pessoa'];
const isHandoff=keywords.some(k=>(msg.content||'').toLowerCase().includes(k.toLowerCase()));
return[{json:{...msg,cliente,isHandoff}}];

const d = $('Merge e Handoff Check').first().json;
// Short-circuit: audio/image blocked
if (d.forceResposta) {
  const forced = JSON.stringify({resposta: d.forceResposta, intencao: 'CONTINUA', pedido: null});
  return [{ json: { ...d, messages: [
    {role:'system', content:'Reply ONLY with this exact JSON, no changes: ' + forced},
    {role:'user', content:'ok'}
  ], isFirst: false } }];
}
const { cliente } = d;
const pushName = (d.pushName || '').trim();
const content = $('Prepara Conteudo').first().json.contentFinal || d.content || '';

const histBody = $('Busca Historico').first().json.body || [];
const historico = Array.isArray(histBody) ? histBody.reverse() : [];

const leadBody = $('Busca Lead').first().json.body || [];
const lead = Array.isArray(leadBody) && leadBody.length > 0 ? leadBody[0] : null;

const ctxBody = $('Busca Contexto').first().json.body || [];
const catalogoFull = Array.isArray(ctxBody) ? ctxBody : [];

// Ã¢â€â‚¬Ã¢â€â‚¬ DISPONIBILIDADE: leitura defensiva Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// Lida com fullResponse (body como array) e sem fullResponse (json ÃƒÂ© o array)
const _dispRaw = $('Busca Disponibilidade').first().json;
let dispBody;
if (Array.isArray(_dispRaw)) {
  dispBody = _dispRaw;
} else if (_dispRaw && Array.isArray(_dispRaw.body)) {
  dispBody = _dispRaw.body;
} else if (_dispRaw && typeof _dispRaw.body === 'string') {
  try { dispBody = JSON.parse(_dispRaw.body); } catch(e) { dispBody = []; }
} else {
  dispBody = [];
}
const disponibilidade = Array.isArray(dispBody) ? dispBody : [];

const cdBody = $('Busca Conteudo Dinamico').first().json.body || [];
const conteudoDinamico = Array.isArray(cdBody) ? cdBody : [];

let catalogoContexto;

if (cliente.catalog_source === 'woocommerce' || disponibilidade.length === 0) {
  // WooCommerce: disponibilidade controlada pelo campo `disponivel` (sincronizado do estoque)
  // Manual sem regras: usa todos os itens ativos
  catalogoContexto = catalogoFull;
} else {
  // BRT (UTC-3) Ã¢â‚¬â€ independente do timezone do servidor N8N
  const _agora    = new Date();
  const _brt      = new Date(_agora.getTime() - 3 * 60 * 60 * 1000);
  const diaAtual  = _brt.getUTCDay();    // 0=Dom 1=Seg 2=Ter 3=Qua 4=Qui 5=Sex 6=Sab
  const diaStr    = String(diaAtual);    // comparaÃƒÂ§ÃƒÂ£o por string (evita coerÃƒÂ§ÃƒÂ£o de tipo)
  const hora      = _brt.getUTCHours();
  const hojeISO   = _brt.toISOString().split('T')[0];

  const idsAtivos   = new Set();
  let   regraGlobal = false;

  // Helper: normaliza dias_semana para array de strings
  function parseDias(rawDias) {
    if (!rawDias) return [];
    let arr = rawDias;
    if (typeof arr === 'string') {
      try { arr = JSON.parse(arr); } catch(e) { return []; }
    }
    if (typeof arr === 'number') return [String(arr)];
    if (!Array.isArray(arr)) return [];
    return arr.map(d => String(d).trim());
  }

  for (const disp of disponibilidade) {
    if (disp.ativo === false) continue;   // null/undefined = ativo
    let match = false;

    const tipo = disp.condicao_tipo || '';

    if (tipo === 'dia_semana') {
      const diasArr = parseDias(disp.dias_semana);
      if (diasArr.length > 0) {
        match = diasArr.includes(diaStr);
      } else {
        // formato legado: condicao_valor = '3'
        const val = String(disp.condicao_valor || '').trim();
        match = val !== '' && val === diaStr;
      }
    } else if (tipo === 'periodo') {
      const ini = disp.data_inicio || null;
      const fim = disp.data_fim    || null;
      const dentroData = (!ini || hojeISO >= ini) && (!fim || hojeISO <= fim);
      if (dentroData) {
        const diasArr = parseDias(disp.dias_semana);
        match = diasArr.length === 0 || diasArr.includes(diaStr);
      }
    } else if (tipo === 'turno') {
      const val = disp.condicao_valor || '';
      if (val === 'manha')  match = hora < 12;
      if (val === 'almoco') match = hora >= 11 && hora < 15;
      if (val === 'tarde')  match = hora >= 15 && hora < 18;
      if (val === 'jantar') match = hora >= 18;
    } else if (tipo === 'unidade') {
      match = true;
    }

    if (match) {
      if (!disp.catalogo_id) {
        regraGlobal = true;
      } else {
        idsAtivos.add(disp.catalogo_id);
      }
    }
  }

  if (regraGlobal) {
    catalogoContexto = catalogoFull;
  } else if (idsAtivos.size > 0) {
    catalogoContexto = catalogoFull.filter(c => idsAtivos.has(c.id));
  } else {
    catalogoContexto = [];
  }
}

let ctxBlock = '';
if (catalogoContexto.length === 0 && disponibilidade.length > 0) {
  // HÃƒÂ¡ regras de disponibilidade mas nenhuma bate hoje Ã¢â€ â€™ aviso explÃƒÂ­cito
  const diasSemana = ['domingo','segunda','terca','quarta','quinta','sexta','sabado'];
  const diaHoje = diasSemana[new Date(new Date().getTime() - 3*60*60*1000).getUTCDay()];
  ctxBlock = `CARDAPIO HOJE (${diaHoje.toUpperCase()}): NENHUM ITEM DISPONIVEL.\nINSTRUCAO OBRIGATORIA: NAO mencione, invente, sugira ou cite nenhum produto ou prato.\nInforme ao cliente que o cardapio de hoje ainda nao esta disponivel ou que nao ha opcoes para ${diaHoje}.\nSugira que ele retorne em outro dia ou pergunte sobre horarios de funcionamento.\nEsta regra sobrepos qualquer outra Ã¢â‚¬â€ mesmo que o cliente insista, nao cite produtos.`;
} else if (catalogoContexto.length > 0) {
  const byCat = {};
  for (const p of catalogoContexto) {
    // Itens de composiÃ§Ã£o (prato_principal/adicional) nÃ£o aparecem no cardÃ¡pio do cliente
    if (p.tipo === 'prato_principal' || p.tipo === 'adicional') continue;
    const cat = p.categoria || '';
    if (!byCat[cat]) byCat[cat] = [];
    let extraStr = '';
    if (p.extras && typeof p.extras === 'object') {
      extraStr = Object.entries(p.extras)
        .filter(([k, v]) => v !== null && v !== '')
        .map(([k, v]) => `${k}: ${v === true ? 'Sim' : v === false ? 'N?o' : v}`)
        .join(' | ');
    }
    const precoStr = p.divulga_preco !== false ? ` R$${Number(p.preco||0).toFixed(2)}` : ' [PRECO: SOB CONSULTA]';
    const destaqueKeys = Array.isArray(p.destaque) ? p.destaque : [];
    // Mark highlighted extras
    let extraStrFinal = '';
    if (p.extras && typeof p.extras === 'object') {
      extraStrFinal = Object.entries(p.extras)
        .filter(([k, v]) => v !== null && v !== '' && k !== 'permitetrocas')
        .map(([k, v]) => {
          const val = v === true ? 'Sim' : v === false ? 'N?o' : v;
          return destaqueKeys.includes(k) ? `? ${k}: ${val}` : `${k}: ${val}`;
        })
        .join(' | ');
    }
    byCat[cat].push(`${p.nome}${precoStr}${p.descricao ? ' - ' + p.descricao : ''}${extraStrFinal ? ' | ' + extraStrFinal : ''}`);
  }
  ctxBlock = 'CATALOGO:\n';
  for (const [cat, itens] of Object.entries(byCat)) {
    if (cat) ctxBlock += `${cat}:\n`;
    ctxBlock += itens.map(i => `  - ${i}`).join('\n') + '\n';
  }
}


// Ã¢â€â‚¬Ã¢â€â‚¬ Trocas: listas de proteinas e acompanhamentos Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
// Itens que permitem troca (suporte a coluna nova + campo extra legado)
const itensTroca = catalogoContexto.filter(function(p){
  if (p.tipo === 'prato_principal' || p.tipo === 'adicional') return false;
  return p.permitetrocas === true || (p.extras && p.extras.permitetrocas === true);
});
// Acompanhamentos disponÃ­veis: derivados das marmitas de hoje que permitem troca
var acpSet = {};
itensTroca.forEach(function(p) {
  if (p.extras && p.extras.acompanhamentos) {
    String(p.extras.acompanhamentos).split(/,|\se\s/).forEach(function(a) {
      var t = a.trim();
      if (t) acpSet[t.toLowerCase()] = t;
    });
  }
});
var acpNomes = Object.keys(acpSet);

// Injeta listas no contexto para perguntas gerais
if (itensTroca.length > 0) {
  var linhasP = itensTroca.map(function(p){
    var prot = p.extras && p.extras.proteina ? p.extras.proteina : '';
    return '  - ' + p.nome + (prot ? ' / ' + prot : '');
  }).join('\n');
  ctxBlock += '\nPROTEINAS DISPONIVEIS PARA MARMITA:\n' + linhasP + '\n';
}
if (acpNomes.length > 0) {
  ctxBlock += '\nACOMPANHAMENTOS DISPONIVEIS PARA TROCA:\n  ' + Object.values(acpSet).join(', ') + '\n';
}

// Ã¢â€â‚¬Ã¢â€â‚¬ Deteccao e validacao antecipada de trocas Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬Ã¢â€â‚¬
var msgLower = (content || '').toLowerCase();
var pedeTroca = msgLower.includes('troca') || msgLower.includes('substitui')
             || msgLower.includes('em vez') || msgLower.includes('no lugar')
             || msgLower.includes('trocar') || msgLower.includes('trocando');

if (pedeTroca && !d.forceResposta) {

  // 1. Identifica proteina mencionada na mensagem atual
  var proteinaSolicitada = null;
  itensTroca.forEach(function(p) {
    if (proteinaSolicitada) return;
    var nomeLower  = p.nome.toLowerCase();
    var protLower  = p.extras && p.extras.proteina ? p.extras.proteina.toLowerCase() : '';
    // Match por palavras significativas (>3 chars) do nome ou proteina
    var palavras = (nomeLower + ' ' + protLower).split(/\s+/).filter(function(w){ return w.length > 3; });
    if (palavras.some(function(w){ return msgLower.includes(w); })) {
      proteinaSolicitada = p;
    }
  });

  // 2. Identifica troca de acompanhamento: "X por Y" onde X e Y estao no acpSet
  var acpDe = null, acpPara = null;
  var tokens = msgLower.replace(/[,\.!?]/g, ' ').split(/\s+/);
  for (var ti = 0; ti < tokens.length; ti++) {
    if (tokens[ti] === 'por' && ti > 0) {
      var antes  = tokens.slice(Math.max(0, ti - 4), ti).join(' ');
      var depois = tokens.slice(ti + 1, Math.min(tokens.length, ti + 5)).join(' ');
      acpNomes.forEach(function(acpL) {
        if (!acpDe  && antes.includes(acpL))  acpDe  = acpL;
        if (!acpPara && depois.includes(acpL)) acpPara = acpL;
      });
      // Aceita qualquer item apÃ³s "por" mesmo fora do pool (ex: "fritas" nÃ£o catalogada)
      if (!acpPara && depois.trim()) acpPara = depois.trim();
    }
  }

  // 3. Se so troca acompanhamento (sem proteina na msg), busca proteina no historico
  var baseItem = proteinaSolicitada;
  if (!baseItem && historico.length > 0) {
    // Junta todo o historico recente (ultimas 6 msgs) para buscar
    var textoHist = historico.slice(-6).map(function(m){ return m.content || ''; }).join(' ').toLowerCase();
    itensTroca.forEach(function(p) {
      if (baseItem) return;
      var nomeLower  = p.nome.toLowerCase();
      var protLower  = p.extras && p.extras.proteina ? p.extras.proteina.toLowerCase() : '';
      var palavras = (nomeLower + ' ' + protLower).split(/\s+/).filter(function(w){ return w.length > 3; });
      // Basta 1 palavra significativa no historico
      if (palavras.some(function(w){ return textoHist.includes(w); })) {
        baseItem = p;
      }
    });
  }

  // 4. Monta resposta forcada
  var confirmacao = null;

  if (baseItem && acpDe && acpPara) {
    // Proteina identificada + troca de acompanhamento
    var protNome    = (baseItem.extras && baseItem.extras.proteina) || baseItem.nome;
    var acpOriginal = (baseItem.extras && baseItem.extras.acompanhamentos) || '';
    var valDe   = acpSet[acpDe]  || acpDe;
    var valPara = acpSet[acpPara] || acpPara;
    var reAcp   = new RegExp(valDe.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'gi');
    var acpFinal = acpOriginal ? acpOriginal.replace(reAcp, valPara) : valPara;
    confirmacao = 'Anotado! Marmita de ' + protNome + ' com ' + acpFinal + '. Posso confirmar o pedido?';

  } else if (baseItem && !acpDe) {
    // So troca de proteina
    var protNome    = (baseItem.extras && baseItem.extras.proteina) || baseItem.nome;
    var acpOriginal = (baseItem.extras && baseItem.extras.acompanhamentos) || '';
    confirmacao = 'Anotado! Marmita de ' + protNome + (acpOriginal ? ' com ' + acpOriginal + '.' : '.') + ' Posso confirmar o pedido?';

  } else if (!baseItem && acpDe && acpPara) {
    // Troca de acompanhamento sem proteina identificada Ã¢â‚¬â€ confirma a troca genericamente
    var valDe   = acpSet[acpDe]  || acpDe;
    var valPara = acpSet[acpPara] || acpPara;
    confirmacao = 'Anotado! ' + valDe + ' substituido por ' + valPara + '. Pode confirmar o pedido com esse ajuste?';
  }

  if (confirmacao) {
    var forcedJson = JSON.stringify({resposta: confirmacao, intencao: 'CONTINUA', pedido: null});
    return [{ json: Object.assign({}, d, { messages: [
      {role: 'system', content: 'Responda APENAS com este JSON exato sem nenhuma alteracao: ' + forcedJson},
      {role: 'user', content: 'ok'}
    ] }) }];
  }
}

for (const cd of conteudoDinamico) {
  const escopoStr = cd.escopo_tipo && cd.escopo_tipo !== 'geral'
    ? ` [Escopo: ${cd.escopo_tipo === 'categoria' ? 'Categoria ' : 'Item '}${cd.escopo_valor || ''}]`
    : '';
  ctxBlock += `\n${(cd.tipo||'INFO').toUpperCase()}${cd.titulo ? ' - ' + cd.titulo : ''}${escopoStr}:\n${cd.conteudo}\n`;
}

const nomePushName = pushName && pushName !== '.' && pushName.length > 1 ? pushName : '';
const isRetorno = d.crm_retorno === true;
const nomeBlock = `

PROTOCOLO DE IDENTIFICACAO DO CLIENTE (siga rigorosamente a ordem abaixo, analisando o historico):
1. Se for a PRIMEIRA mensagem (historico vazio): pergunte o nome do cliente de forma cordial, integrando naturalmente ao atendimento.
2. Se ja perguntou o nome mas o cliente NAO respondeu com um nome${nomePushName ? ` e existe o nome do WhatsApp "${nomePushName}"` : ''}: pergunte "Posso te chamar de ${nomePushName || '[nome do WhatsApp]'}?"
3. Se o cliente confirmar o nome do WhatsApp ou informar outro nome: use esse nome em toda a conversa.
4. Se o cliente recusar ou nao informar nenhum nome: use "Sr." ou "Sra." para se referir a ele(a).
Nao repita a pergunta de nome mais de duas vezes.`;

const basePrompt = cliente.system_prompt || `Voce e o assistente virtual de ${cliente.nome_negocio}. Atenda com cordialidade e foco no negocio.`;

const identidadeBlock = `

IDENTIDADE (regra absoluta, sem excecoes):
Voce e o consultor de ${cliente.nome_negocio}. NUNCA mencione que e IA, robo, sistema automatizado, assistente virtual ou qualquer tecnologia.
- Nao se apresente como humano nem como digital - apenas como consultor ou atendente do negocio.
- Se o cliente perguntar se e IA ou robo: desvie com naturalidade, sem confirmar nem negar. Ex: "Estou aqui para te ajudar! O que posso fazer por voce?"
- Nunca use frases como "como IA", "fui treinado", "sou um modelo", "como assistente virtual", "consultor digital".

TOM E LINGUAGEM NATURAL (regra obrigatoria):
Escreva como um consultor humano escreveria no WhatsApp â€” direto, caloroso, sem formalidade excessiva.
PROIBIDO usar estas frases ou similares (sao marcas tipicas de IA e parecem roboticas):
- "Se algum desses produtos chamou sua atencao..."
- "Estou aqui para ajudar!", "Estou a disposicao!", "Nao hesite em me contatar"
- "Espero ter ajudado!", "Fico feliz em ajudar!", "Foi um prazer!"
- "Com certeza!", "Absolutamente!", "Excelente escolha!"
- "Qualquer duvida, estou a disposicao!"
- "Como posso te ajudar hoje?" (exceto na primeira mensagem)
- Fechamentos genericos do tipo "Se precisar de mais alguma coisa, e so falar!"
Em vez disso: termine com uma pergunta direta e especifica sobre o que o cliente disse, ou com uma sugestao concreta. Seja natural como numa conversa real.`;

const focoBlock = `

FOCO DO NEGOCIO:
Voce representa exclusivamente ${cliente.nome_negocio}. Siga estas regras:
- Mantenha sempre o foco no setor de atuacao do negocio.
- Se o cliente perguntar algo fora do escopo do negocio: responda de forma breve e educada, sem aprofundar, e redirecione naturalmente para o universo do negocio.
