// Verificar se est? em hor?rio comercial (America/Sao_Paulo)
// Segunda a Sexta: 8h30 ?s 17h30
// S?bado: 9h ?s 13h
// Domingo: Fechado

const now = new Date();
const formatter = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Sao_Paulo',
  year: 'numeric',
  month: '2-digit',
  day: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit',
  hour12: false,
  weekday: 'long'
});

const parts = formatter.formatToParts(now);
const dateTimeParts = {};
parts.forEach(({type, value}) => {
  dateTimeParts[type] = value;
});

const weekday = dateTimeParts.weekday; // Monday, Tuesday, etc
const hour = parseInt(dateTimeParts.hour);
const minute = parseInt(dateTimeParts.minute);
const timeInMinutes = hour * 60 + minute;

let dentroHorario = false;

if (weekday === 'Sunday') {
  // Domingo fechado
  dentroHorario = false;
} else if (weekday === 'Saturday') {
  // S?bado: 9h ?s 13h (540 a 780 minutos)
  dentroHorario = timeInMinutes >= 540 && timeInMinutes < 780;
} else {
  // Segunda a Sexta: 8h30 ?s 17h30 (510 a 1050 minutos)
  dentroHorario = timeInMinutes >= 510 && timeInMinutes < 1050;
}

// Passar todos os dados necess?rios adiante
const inputData = $input.first().json;
const chatId = inputData.result; // ID do chat criado
const phone = $('Prepara Dispatch').first().json.phone;
const instance = $('Prepara Dispatch').first().json.instance;

return [{
  json: {
    dentroHorario,
    chatId,
    phone,
    instance,
    weekday,
    hour,
    minute,
