    if (!rawDias) return [];
    let arr = rawDias;
    if (typeof arr === 'string') {
      try { arr = JSON.parse(arr); } catch(e) { return []; }
    }
    if (typeof arr === 'number') return [String(arr)];
    if (!Array.isArray(arr)) return [];
    return arr.map(d => String(d).trim());
