// Escape literal newlines ONLY inside JSON string values (not structural whitespace)
function fixJsonStrings(str){
  let out="",inStr=false,esc=false;
  for(let i=0;i<str.length;i++){
    const ch=str[i];
    if(esc){out+=ch;esc=false;}
    else if(ch==="\\"&&inStr){out+=ch;esc=true;}
    else if(ch==='"'){inStr=!inStr;out+=ch;}
    else if((ch==="\n"||ch==="\r")&&inStr){out+="\\n";}
    else{out+=ch;}
  }
  return out;
}

