// Dados originais do webhook (v?m do n? E Audio, que ? um IF e preserva $json)
const orig = $('E Audio1').first().json;
const raw = orig.rawData || {};

// Resposta da Evolution API (getBase64FromMediaMessage)
const busca = $input.first().json;

// Tenta base64 em ordem de prioridade
let base64 = orig.audioBase64 ||
  raw.base64 ||
  raw.message?.base64 ||
  raw.message?.audioMessage?.base64 ||
  busca.base64 ||
  busca.data?.base64 ||
  '';

// Remove prefixo data URI se presente (ex: 'data:audio/ogg;base64,XXXXX')
if (base64 && base64.includes(',')) base64 = base64.split(',')[1];

if (!base64) {
  const keysB = Object.keys(busca);
  return [{ json: { ...orig, transcricao: `[?udio recebido, mas base64 n?o encontrado. Resposta Evolution: ${keysB.join(',')} | status: ${busca.status || '?'}]` } }];
}

const mimeType = (orig.audioMime || raw.message?.audioMessage?.mimetype || 'audio/ogg').split(';')[0].trim();
const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('mpeg') ? 'mp3' : 'ogg';
return [{
  json: { ...orig },
  binary: { audio: { data: base64, mimeType, fileName: `audio.${ext}` } }
}];

const item = $input.first();
// Converte Audio sempre espalha mergeData no json (tanto fallback quanto sucesso)
const cliente = item.json.cliente || {};

// Se Converte Audio j? retornou fallback (sem base64), passa adiante
if (item.json.transcricao) {
  return [{ json: item.json }];
}

// Determina provider do Whisper
const whisperProvider = (cliente.whisper_provider || 'openai').toLowerCase();
let whisperUrl, whisperModel;
if (whisperProvider === 'groq') {
  whisperUrl = 'https://api.groq.com/openai/v1/audio/transcriptions';
  whisperModel = 'whisper-large-v3';
} else {
  whisperUrl = 'https://api.openai.com/v1/audio/transcriptions';
  whisperModel = 'whisper-1';
}

// Prioridade: whisper_api_key > ia_api_key (s? se provider for openai/groq)
const iaProvider = (cliente.ia_provider || '').toLowerCase();
const iaKeyValida = ['openai','groq'].includes(iaProvider) ? (cliente.ia_api_key || '') : '';
const whisperApiKey = (cliente.whisper_api_key || iaKeyValida || '').trim();

if (!whisperApiKey) {
  return [{ json: { ...item.json, transcricao: '[?udio recebido - configure a chave da IA no cadastro do neg?cio para habilitar transcri??o]' } }];
}

return [{
  json: { ...item.json, whisperUrl, whisperModel, whisperApiKey },
  binary: item.binary
}];

const prepData = $('Prepara Whisper1').first().json;

// Se j? tem fallback (sem base64 ou sem chave), usa direto
if (prepData.transcricao) {
