const stopwords=new Set(['cÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡psulas','capsulas','comprimidos','doses','gotas','sachÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Âª','sache','vitamina','vitaminas','natural','suplemento','extrato','complexo','forte','plus','max','super','ultra','nano','mini','mega','cÃƒÆ’Ã†â€™Ãƒâ€šÃ‚Â¡ps','caps']);
